INKER DETECTION ===\" -Fore Cyan\n$linkPath = (Get-Command link.exe -ErrorAction SilentlyContinue)\nif($linkPath) {\n    Write-Host \"[FOUND] link.exe: $($linkPath.Source)\" -Fore Green\n} else {\n    Write-Host \"[NOT IN PATH] link.exe not found in PATH\" -Fore Yellow\n    \n    # Search in common VS installation paths\n    $vsPaths = @(\n        \"C:\\Program Files\\Microsoft Visual Studio\\*\\*\\VC\\Tools\\MSVC\\*\\bin\\Hostx64\\x64\\link.exe\",\n        \"C:\\Program Files (x86)\\Microsoft Visual Studio\\*\\*\\VC\\Tools\\MSVC\\*\\bin\\Hostx64\\x64\\link.exe\"\n    )\n    \n    $found = $false\n    foreach($pattern in $vsPaths) {\n        $linkFiles = Get-ChildItem $pattern -ErrorAction SilentlyContinue\n        if($linkFiles) {\n            Write-Host \"[FOUND] link.exe: $($linkFiles[0].FullName)\" -Fore Green\n            $found = $true\n            break\n        }\n    }\n    \n    if(!$found) {\n        Write-Host \"[ERROR] link.exe not found anywhere. Install Visual Studio Build Tools.\" -Fore Red\n    }\n}\n\n# Check for lib.exe\n$libPath = (Get-Command lib.exe -ErrorAction SilentlyContinue)\nif($libPath) {\n    Write-Host \"[FOUND] lib.exe: $($libPath.Source)\" -Fore Green\n} else {\n    Write-Host \"[NOT FOUND] lib.exe not available (optional for static libraries)\" -Fore Yellow\n}\n\nWrite-Host \"`n=== BUILD RECOMMENDATION ===\" -Fore Cyan\n\n# Determine build strategy\nif($ml64Path -or $found) {\n    Write-Host \"✓ Can use standard Microsoft MASM toolchain\" -Fore Green\n    Write-Host \"  Strategy: .asm → ml64.exe → .obj → link.exe → RawrXD.exe\" -Fore White\n} else {\n    Write-Host \"⚠ Microsoft MASM toolchain not available\" -Fore Yellow\n    Write-Host \"  Alternative: Use PowerLang linker or install Visual Studio Build Tools\" -Fore White\n    Write-Host \"  Install: https://visualstudio.microsoft.com/visual-cpp-build-tools/\" -Fore Cyan\n}\n\nWrite-Host \"`n=== DIRECTORY STRUCTURE ===\" -Fore Cyan\n$buildDir = \"$Root\\build\"\nif(!(Test-Path $buildDir)) {\n    Write-Host \"Creating build directory: $buildDir\" -Fore Yellow\n    New-Item -ItemType Directory -Path $buildDir -Force | Out-Null\n}\n\n$objDir = \"$buildDir\\obj\"\n$libDir = \"$buildDir\\lib\"\n$binDir = \"$buildDir\\bin\"\n\nforeach($dir in @($objDir, $libDir, $binDir)) {\n    if(!(Test-Path $dir)) {\n        New-Item -ItemType Directory -Path $dir -Force | Out-Null\n        Write-Host \"Created: $dir\" -Fore Gray\n    } else {\n        Write-Host \"Exists: $dir\" -Fore Gray\n    }\n}\n\nWrite-Host \"`n=== ENVIRONMENT CHECK COMPLETE ===\" -Fore Magenta\nWrite-Host \"Ready to proceed with monolithic build if toolchain is available.\" -Fore Green\n